UPDATE tb_csm_semotong_review 
SET
   content			= #{content}
   ,score			= #{score}
   ,modified_id		= #{modifiedId}
WHERE id = #{id}

mapper.select:
    	SELECT 
    		IFNULL(MIN(score), 0) AS min_score,
		 	IFNULL(MAX(score), 0) AS max_score,
		 	IFNULL(AVG(score), 0) AS avg_score,
		 	COUNT(1) AS cnt
 		FROM tb_csm_semotong_review
 		WHERE 1=1

            AND plan_id = #{planId}



            AND company_id = #{companyId}



        	AND review_type = #{reviewType}
